const TIMEZONE = 'America/Halifax';

const WEEKDAYS = {
  monday: 1, mon: 1, tuesday: 2, tue: 2, tues: 2, wednesday: 3, wed: 3,
  thursday: 4, thu: 4, thurs: 4, friday: 5, fri: 5,
  saturday: 6, sat: 6, sunday: 7, sun: 7
};

const MONTHS = {
  january: 1, jan: 1, february: 2, feb: 2, march: 3, mar: 3, april: 4, apr: 4,
  may: 5, june: 6, jun: 6, july: 7, jul: 7, august: 8, aug: 8,
  september: 9, sept: 9, sep: 9, october: 10, oct: 10,
  november: 11, nov: 11, december: 12, dec: 12
};

const weekdayNames = Object.keys(WEEKDAYS).join('|');
const monthNames = Object.keys(MONTHS).join('|');

function soonestWeekday(now, target) {
  const start = now.startOf('day');
  let delta = (target - start.weekday + 7) % 7;
  if (delta === 0) delta = 7;
  return start.plus({ days: delta });
}

function monthDay(now, month, day) {
  const start = now.startOf('day');
  let candidate = start.set({ month: month, day: day });
  if (!candidate.isValid) return null;
  if (candidate < start) candidate = candidate.plus({ years: 1 });
  return candidate;
}

const RULES = [
  { id: 'in N days', pattern: new RegExp('\\bin (\\d{1,3}) days?\\b'), resolve: (now, m) => now.startOf('day').plus({ days: Number(m[1]) }) },
  { id: 'next weekday', pattern: new RegExp('\\bnext (' + weekdayNames + ')\\b'), resolve: (now, m) => soonestWeekday(now, WEEKDAYS[m[1]]) },
  { id: 'by weekday', pattern: new RegExp('\\bby (' + weekdayNames + ')\\b'), resolve: (now, m) => soonestWeekday(now, WEEKDAYS[m[1]]) },
  { id: 'on month day', pattern: new RegExp('\\bon (' + monthNames + ') (\\d{1,2})\\b'), resolve: (now, m) => monthDay(now, MONTHS[m[1]], Number(m[2])) },
  { id: 'tomorrow', pattern: new RegExp('\\btomorrow\\b'), resolve: (now) => now.startOf('day').plus({ days: 1 }) },
  { id: 'today', pattern: new RegExp('\\btoday\\b'), resolve: (now) => now.startOf('day') }
];

const now = DateTime.now().setZone(TIMEZONE);
const results = [];

for (const item of $input.all()) {
  const body = String(item.json.messageBody || '');
  const haystack = String(item.json.searchText || body.toLowerCase());
  let dueIso = '';
  let matchedRule = '';
  let matchedPhrase = '';
  let title = body;

  for (const rule of RULES) {
    const found = haystack.match(rule.pattern);
    if (!found) continue;
    const due = rule.resolve(now, found);
    if (!due || !due.isValid) continue;
    dueIso = due.toISODate();
    matchedRule = rule.id;
    matchedPhrase = body.substring(found.index, found.index + found[0].length);
    title = body.slice(0, found.index) + ' ' + body.slice(found.index + found[0].length);
    break;
  }

  title = title.replace(new RegExp('\\s+', 'g'), ' ').trim();
  title = title.replace(new RegExp('^[,.;:-]+'), '').replace(new RegExp('[,.;:-]+$'), '').trim();
  if (!title) title = 'Untitled SMS task';

  results.push({
    json: {
      title: title,
      dueIso: dueIso,
      matchedRule: matchedRule,
      matchedPhrase: matchedPhrase,
      timezone: TIMEZONE,
      fromNumber: item.json.fromNumber || '',
      receivedAt: item.json.receivedAt || '',
      originalBody: body
    }
  });
}

return results;
